# InsightLab scaffold restore — run inside your empty insight-lab clone
# Usage: powershell -ExecutionPolicy Bypass -File restore-insight-lab.ps1

$ErrorActionPreference = "Stop"
$bundleB64 = @"

"@

$bundlePath = Join-Path $PSScriptRoot "insight-lab.bundle"
[System.IO.File]::WriteAllBytes($bundlePath, [Convert]::FromBase64String($bundleB64))

Write-Host "Bundle written. Pulling scaffold into current repo..."
git pull $bundlePath main
if ($LASTEXITCODE -ne 0) {
    Write-Host "If pull failed, ensure you are in the insight-lab repo root with an empty main branch."
    exit 1
}

Write-Host "Done! Push with: git push -u origin main"
Remove-Item $bundlePath -ErrorAction SilentlyContinue
